"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["8208"],{56670(e,a,o){o.r(a),o.d(a,{default:()=>r});var i=o(74848),n=o(47643),t=JSON.parse('{"id":250,"it":{"title":"ciclo di interrogazione","prompt":"Your task is to automatically take turns asking and answering questions. We\u2019ll begin with an initial question. Then go on answering and asking in this pattern:\\nQuestion: The initial question\\nAnswer: The answer to the initial question\\nQuestion: The question about the reason for the previous answer\\nAnswer: The answer to the previous question\\nQuestion:\\nKeep asking about the reason for the last answer. Stop only when the answer is \\"That\'s the way it is\\" or \\"We don\'t know for now\\". Each question and answer should be a single sentence with no more than 20 words. Add \\"Q: \\" before each question and \\"A: \\" before each answer.\\nAsk and answer in \\"English\\" regardless of the language I use. Don\u2019t show the translation process. Just write questions and answers in the destination language. Respond in Italian. Now, the initial question is: [domanda iniziale del ciclo]","description":"Il vostro compito \xe8 quello di fare e rispondere automaticamente a turno alle domande. Inizieremo con una domanda iniziale. Poi continuate a rispondere e a fare domande secondo questo schema: domanda: domanda iniziale risposta: risposta alla domanda iniziale domanda: domanda sul motivo della precedente domanda: domanda sul motivo della precedente risposta risposta: risposta alla precedente domanda domanda: risposta alla precedente domanda: risposta alla precedente domanda: continuate a chiedere il motivo della precedente risposta. Fermarsi solo quando la risposta \xe8 \\"\xc8 cos\xec\\" o \\"Per ora non lo sappiamo\\". Ogni domanda e risposta deve essere una singola frase di non pi\xf9 di 20 parole. Ogni domanda deve essere preceduta da \\"Q:\\" e ogni risposta da \\"A:\\". Porre e rispondere alle domande in cinese, indipendentemente dalla lingua che utilizzo. Non mostrare il processo di traduzione. Scrivete solo le domande e le risposte nella lingua di destinazione.","remark":"Continuare a porre domande intorno a un problema per approfondirne la comprensione. Contributo di @hkfrank996."},"tags":["contribute","mind"],"website":null,"count":1395,"related":[{"id":206,"title":"Assistente per il pensiero profondo","remark":"Allenatevi a pensare in profondit\xe0 fornendo domande di alta qualit\xe0 e valore basate su parole chiave, temi o concetti che affrontano vari aspetti della cognizione, delle emozioni e del comportamento umano. Questo prompt ha una struttura chiara per le risposte ed \xe8 adatto per l\'organizzazione dei concetti. Contributo di @MoeACG."},{"id":196,"title":"deposito","remark":"Offre molte prospettive diverse su cui riflettere. Contributi di @jiuwen624. (Le attuali 6 prospettive non sembrano essere molto diverse e devono essere migliorate)."},{"id":176,"title":"Assistente per le domande","remark":"Porre domande da pi\xf9 punti di vista per stimolare un pensiero pi\xf9 profondo. Contributo di @meishiwanwan."}],"metaTitle":"Loop Logico: Perch\xe9?","metaDescription":"Approfondire? Chiedi \'Perch\xe9?\' continuamente. Esplora cause radice con pattern ricorsivo. Provalo ora.","faq":[{"q":"Il ciclo di domande fa divagare la discussione?","a":"S\xec. Dopo pi\xf9 turni l\'AI pu\xf2 passare dal \xabperch\xe9\xbb alla filosofia spinta. Aggiungi \xabogni 5 turni torna al tema centrale con un riassunto intermedio\xbb. Senza questo \xabpunto di richiamo\xbb il giro diventa infinito e nessuno ricorda la domanda iniziale."},{"q":"Per quali tipi di domande \xe8 adatto?","a":"Per domande con valore esplorativo (\xabperch\xe9 procrastino\xbb, \xabcos\'\xe8 una vita buona\xbb). Per domande meccaniche (\xabcome reinstallo Windows\xbb) \xe8 assurdo: la risposta non richiede filosofia; per quelle strumentali cerca direttamente."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(n.A,{prompt:t,currentLanguage:"it"})}}}]);